sp_widget.client_script:
api.controller = function() {

    var c = this;

    c.tables = [];
    c.selectedTable = "";
    c.count = 0;
    c.search = "";
    c.loading = false;

    /* Load tables on init */
    c.loadTables = function() {

        c.loading = true;

        c.server.get({ action: "load_tables" }).then(function(res){
            c.tables = res.data.tables;
            c.loading = false;
        });
    };

    /* When table selected */
    c.onTableChange = function() {

        if (!c.selectedTable) return;

        c.loading = true;

        c.server.get({
            action: "get_count",
            table: c.selectedTable
        }).then(function(res){

            c.count = res.data.count;
            c.loading = false;
        });
    };

    c.loadTables();
};

sp_widget.css:
/* ===== Wrapper Card ===== */
.migration-wrapper {
  background: #ffffff;
  padding: 30px;
  border-radius: 14px;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.06);
  max-width: 650px;
  margin: 40px auto;
  transition: all 0.2s ease-in-out;
}

/* ===== Title ===== */
.migration-wrapper h3 {
  margin-bottom: 20px;
  font-weight: 600;
  color: #1f2937;
}

/* ===== Input & Select ===== */
.migration-wrapper input[type="text"],
.migration-wrapper select {
  width: 100%;
  padding: 12px 14px;
  border-radius: 8px;
  border: 1px solid #d1d5db;
  margin-bottom: 16px;
  font-size: 14px;
  transition: all 0.2s ease-in-out;
  background: #f9fafb;
}

/* Focus Effect */
.migration-wrapper input[type="text"]:focus,
.migration-wrapper select:focus {
  outline: none;
  border-color: #0070f3;
  background: #ffffff;
  box-shadow: 0 0 0 3px rgba(0, 112, 243, 0.1);
}

/* ===== Dropdown Hover ===== */
.migration-wrapper select:hover {
  border-color: #9ca3af;
}

/* ===== Record Count Box ===== */
.count-box {
  background: #f0f7ff;
  border-left: 4px solid #0070f3;
  padding: 15px;
  border-radius: 8px;
  margin-top: 10px;
  font-size: 14px;
  font-weight: 500;
  color: #1e3a8a;
}

/* ===== Loading Indicator ===== */
.loading-box {
  margin-top: 15px;
  font-size: 13px;
  color: #6b7280;
  display: flex;
  align-items: center;
  gap: 8px;
}

/* Spinner */
.spinner {
  width: 16px;
  height: 16px;
  border: 2px solid #e5e7eb;
  border-top: 2px solid #0070f3;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ===== Error ===== */
.error {
  background: #fef2f2;
  color: #b91c1c;
  padding: 12px;
  border-radius: 8px;
  border-left: 4px solid #dc2626;
  margin-bottom: 15px;
  font-size: 13px;
}

/* ===== Responsive ===== */
@media (max-width: 768px) {
  .migration-wrapper {
    padding: 20px;
  }
}

sp_widget.script:
(function () {

    data.tables = [];
    data.count = 0;
    data.error = "";

    var connectionId = $sp.getParameter('sys_id');

    if (!connectionId) {
        data.error = "Connection not provided";
        return;
    }

    var connGR = new GlideRecord('x_sysus_data_mig_0_connection');
    if (!connGR.get(connectionId)) {
        data.error = "Connection not found";
        return;
    }

    var username = connGR.getValue('username');
    var password = connGR.getValue('password');
    var baseUrl  = connGR.getValue('url');

    /* ==============================
       LOAD TABLES
    ============================== */

    if (input && input.action === "load_tables") {

        try {

            var rm = new sn_ws.RESTMessageV2();
            rm.setEndpoint(baseUrl + "/api/now/table/sys_db_object?sysparm_query=active=true^nameNOT LIKEsys_&sysparm_fields=name,label&sysparm_limit=500");
            rm.setHttpMethod("GET");
            rm.setBasicAuth(username, password);

            var response = rm.execute();
            var status = response.getStatusCode();

            if (status != 200) {
                data.error = "Failed to fetch tables. Status: " + status;
                return;
            }

            var body = JSON.parse(response.getBody());
            data.tables = body.result || [];

        } catch (e) {
            data.error = e.message;
        }
    }

    /* ==============================
       LOAD COUNT
    ============================== */

    if (input && input.action === "get_count") {

        if (!input.table) {
            data.error = "Table not provided";
            return;
        }

        try {

            var rm2 = new sn_ws.RESTMessageV2();
            rm2.setEndpoint(baseUrl + "/api/now/table/" + input.table + "?sysparm_limit=1");
            rm2.setHttpMethod("GET");
            rm2.setBasicAuth(username, password);

            var response2 = rm2.execute();
            var status2 = response2.getStatusCode();

            if (status2 != 200) {
                data.error = "Failed to fetch count. Status: " + status2;
                return;
            }

            var total = response2.getHeader("X-Total-Count");

            data.count = total ? parseInt(total, 10) : 0;

        } catch (ex) {
            data.error = ex.message;
        }
    }

})();
